import csv
from statistics import mean, median, stdev
from pathlib import Path


def csv_stats(path: str, column: str) -> dict:
    """Compute basic statistics for a numeric column in a CSV file."""
    values = []
    with open(path, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            try:
                values.append(float(row[column]))
            except (ValueError, KeyError):
                continue

    if not values:
        return {"error": f"No numeric values found in column '{column}'"}

    return {
        "count": len(values),
        "mean": round(mean(values), 2),
        "median": round(median(values), 2),
        "stdev": round(stdev(values), 2) if len(values) > 1 else 0,
        "min": min(values),
        "max": max(values),
    }
